"use client"

import { useEffect, useState } from "react"
import { Github, Linkedin, Twitter, Mail, MapPin } from "lucide-react"
import { MagneticButton } from "./magnetic-button"
import { DoubleArrowDownIcon, ArrowRightIcon} from "@radix-ui/react-icons"


const socialLinks = [
  { icon: Github, href: "https://github.com/MrSalaam", label: "GitHub" },
  { icon: Linkedin, href: "https://linkedin.com/in/olayinka-salaam", label: "LinkedIn" },
  { icon: Twitter, href: "https://x.com/OlayinkaSZN", label: "Twitter" },
  { icon: Mail, href: "mailto:olayinkasalaam.dev@gmail.com", label: "Email" },
]

export function HeroSection() {
  const [displayText, setDisplayText] = useState("")
  const [showCursor, setShowCursor] = useState(true)
  const fullText = "I build things for the web."

  useEffect(() => {
    let index = 0
    const interval = setInterval(() => {
      if (index <= fullText.length) {
        setDisplayText(fullText.slice(0, index))
        index++
      } else {
        clearInterval(interval)
      }
    }, 50)
    return () => clearInterval(interval)
  }, [])

  useEffect(() => {
    const cursorInterval = setInterval(() => {
      setShowCursor((prev) => !prev)
    }, 530)
    return () => clearInterval(cursorInterval)
  }, [])

  return (
    <section className="min-h-screen flex flex-col justify-center py-24 md:py-32 relative px-4 md:px-0">
      
      <div className="grid grid-cols-1 md:grid-cols-12 gap-8 md:gap-16 items-start mt-12 md:mt-0">
        
        {/* Left Side: Massive Serif Typographic Statement */}
        <div className="md:col-span-8 space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-1000">
          <div className="inline-flex items-center gap-3 px-4 py-2 rounded-full bg-secondary border border-border">
            <span className="relative flex h-2 w-2">
              <span className="relative inline-flex rounded-full h-2 w-2 bg-foreground"></span>
            </span>
            <span className="text-xs font-sans font-medium text-foreground tracking-wide uppercase">Available for work</span>
          </div>

          <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-foreground leading-[1.05] tracking-tight">
            Yinka Salaam.
            <br />
            <span className="text-muted-foreground">Frontend Engineer.</span>
          </h1>
        </div>

        {/* Right Side: Editorial Offset Content */}
        <div className="md:col-span-4 md:pt-32 space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-1000 delay-200">
          <p className="text-foreground/80 leading-relaxed font-sans text-lg">
            I craft pristine digital experiences. Focusing on clean code, typographic excellence, and interfaces that feel like a premium gallery.
          </p>

          <div className="flex flex-col gap-4 pt-4">
            <a
              href="#projects"
              className="inline-flex items-center justify-center gap-3 px-8 py-4 bg-foreground text-background font-sans text-sm tracking-wide uppercase rounded-none hover:bg-foreground/90 transition-colors"
            >
              Selected Works
              <ArrowRightIcon className="w-4 h-4" />
            </a>
            
            <div className="flex items-center gap-6 pt-6 border-t border-border mt-4">
              {socialLinks.map((link) => (
                <a
                  key={link.label}
                  href={link.href}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-foreground/60 hover:text-foreground transition-colors"
                  aria-label={link.label}
                >
                  <link.icon className="w-5 h-5 stroke-[1.5]" />
                </a>
              ))}
            </div>
          </div>
        </div>

      </div>

      <div className="absolute bottom-12 left-0 animate-bounce-subtle">
        <a href="#about" className="text-foreground/40 hover:text-foreground transition-colors flex items-center gap-2 font-sans text-sm tracking-widest uppercase">
          <DoubleArrowDownIcon className="w-5 h-5" />
          <span>Scroll</span>
        </a>
      </div>
    </section>
  )
}
