"use client"

import { useRef } from "react"

export function AboutSection() {
  const containerRef = useRef<HTMLElement>(null)

  return (
    <section id="about" className="py-24 md:py-32 scroll-mt-20 border-t border-border" ref={containerRef}>
      <div className="grid grid-cols-1 md:grid-cols-12 gap-8 md:gap-16 items-start">
        
        {/* Left Third: Caption & Title */}
        <div className="md:col-span-4 space-y-4 md:sticky md:top-32">
          <h2 className="text-4xl md:text-5xl font-serif text-foreground tracking-tight">
            Background
          </h2>
          <p className="font-sans text-xs tracking-widest uppercase text-foreground/40">
            01 — The Architect
          </p>
        </div>

        {/* Right Two-Thirds: Content */}
        <div className="md:col-span-8 space-y-12">
          <div className="space-y-8">
            <p className="text-2xl md:text-3xl font-serif text-foreground leading-relaxed">
              Hello. I'm Yinka, a frontend engineer who cares deeply about details, specializing in the modern JavaScript ecosystem.
            </p>
            <div className="h-px w-24 bg-border"></div>
            <p className="text-foreground/70 font-sans leading-relaxed text-lg">
              I prioritize accessibility and fluid UI mechanics to create products that do not just work well, but feel great to use. Fast-forward to today, I've worked for a startup, a designer, and a government organization. 
            </p>
            <p className="text-foreground/70 font-sans leading-relaxed text-lg">
              My main focus these days is building accessible, performant products and digital experiences for a variety of clients. When I'm not coding, I am either gaming, researching the latest design trends, or sharing what I learn.
            </p>
          </div>

          <div className="pt-8">
            <p className="font-sans text-xs tracking-widest uppercase text-foreground/40 mb-8">
              Current Stack
            </p>
            <ul className="grid grid-cols-2 md:grid-cols-3 gap-y-6 gap-x-8 font-sans text-sm">
              {["TypeScript", "React", "Next.js", "Chakra UI", "Tailwind CSS", "Framer Motion", "Shadcn UI", "TanStack Query"].map((tech) => (
                <li key={tech} className="flex items-center gap-3 text-foreground/80 group">
                  <span className="w-8 h-px bg-border group-hover:bg-foreground transition-colors"></span>
                  <span className="tracking-wide">{tech}</span>
                </li>
              ))}
            </ul>
          </div>
        </div>

      </div>
    </section>
  )
}
