"use client"

const experiences = [
  {
    company: "Learnille",
    role: "Frontend Developer",
    period: "2025 - Present",
    description: "Working on admin dashboard interfaces with a focus on component architecture and performance.",
    technologies: ["TypeScript", "React", "Tanstack Query", "Chakra UI"],
  },
  {
    company: "S.A Ayilara",
    role: "Frontend Developer",
    period: "2025",
    description: "Designed and developed a portfolio website. Reduced bundle size by 35% through code splitting.",
    technologies: ["React", "TailwindCSS", "TypeScript", "Shadcn UI"],
  },
  {
    company: "MIC",
    role: "Frontend Developer Intern",
    period: "March - September 2025",
    description: "Developed a responsive website and collaborated with design to implement accessible interfaces.",
    technologies: ["HTML", "CSS", "JavaScript"],
  },
]

export function ExperienceSection() {
  return (
    <section id="experience" className="py-24 md:py-32 scroll-mt-20 border-t border-border">
      <div className="grid grid-cols-1 md:grid-cols-12 gap-8 md:gap-16 items-start">
        {/* Left: Title */}
        <div className="md:col-span-4 space-y-4 md:sticky md:top-32">
          <h2 className="text-4xl md:text-5xl font-serif text-foreground tracking-tight">
            Experience
          </h2>
          <p className="font-sans text-xs tracking-widest uppercase text-foreground/40">
            04 — The Journey
          </p>
        </div>

        {/* Right: Timeline */}
        <div className="md:col-span-8 space-y-16 pt-2">
          {experiences.map((exp, index) => (
            <div key={index} className="relative group">
              <div className="flex flex-col md:flex-row md:justify-between md:items-baseline mb-4">
                <h3 className="text-2xl font-serif text-foreground">
                  {exp.role} <span className="text-foreground/40 font-sans text-lg">— {exp.company}</span>
                </h3>
                <span className="font-mono text-sm text-foreground/50 mt-2 md:mt-0 tracking-tight">
                  {exp.period}
                </span>
              </div>
              
              <p className="text-foreground/70 font-sans leading-relaxed text-lg max-w-2xl mb-6">
                {exp.description}
              </p>

              <div className="flex flex-wrap gap-3">
                {exp.technologies.map((tech) => (
                  <span key={tech} className="font-sans text-xs tracking-wide text-foreground/60 border border-border px-3 py-1 rounded-full">
                    {tech}
                  </span>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
